document.querySelectorAll("[data-dash-bar-pct]").forEach(function(el){var v=el.getAttribute("data-dash-bar-pct");null!=v&&""!==v&&(el.style.height=v+"%")}),document.querySelectorAll("[data-dash-width-pct]").forEach(function(el){var v=el.getAttribute("data-dash-width-pct");null!=v&&""!==v&&(el.style.width=v+"%")});